def set_seed(seed: int) -> None:
    random.seed(seed)
    np.random.seed(seed)


def sha256_file(path: Path) -> str:
    if not path.exists():
        return ""
    h = hashlib.sha256()
    with path.open("rb") as handle:
        for chunk in iter(lambda: handle.read(1024 * 1024), b""):
            h.update(chunk)
    return h.hexdigest()


def safe_float(value: Any, default: float = 0.0) -> float:
    try:
        if pd.isna(value):
            return default
        return float(value)
    except Exception:
        return default


def canonical_inchikey(value: Any) -> str:
    if value is None or pd.isna(value):
        return ""
    return str(value).strip()


def formula_from_smiles(smiles: str | None) -> str | None:
    if not smiles or Chem is None or rdMolDescriptors is None:
        return None
    mol = Chem.MolFromSmiles(smiles)
    if mol is None:
        return None
    return rdMolDescriptors.CalcMolFormula(mol)


def morgan_tanimoto(smiles_a: str | None, smiles_b: str | None) -> float | None:
    if not smiles_a or not smiles_b or Chem is None or AllChem is None or DataStructs is None:
        return None
    mol_a = Chem.MolFromSmiles(smiles_a)
    mol_b = Chem.MolFromSmiles(smiles_b)
    if mol_a is None or mol_b is None:
        return None
    fp_a = rdMolDescriptors.GetMorganFingerprintAsBitVect(mol_a, 2, nBits=2048)
    fp_b = rdMolDescriptors.GetMorganFingerprintAsBitVect(mol_b, 2, nBits=2048)
    return float(DataStructs.TanimotoSimilarity(fp_a, fp_b))


def load_pfas_records(feature_matrix_path: Path, score_matrix_path: Path | None = None) -> tuple[list[SpectrumRecord], dict[str, Any]]:
    if not feature_matrix_path.exists():
        return [], {
            "status": "unavailable",
            "reason": f"PFAS feature matrix not found: {feature_matrix_path}",
            "path": str(feature_matrix_path),
        }

    features = pd.read_csv(feature_matrix_path)
    if "locked_test_used_for_tuning" in features.columns and features["locked_test_used_for_tuning"].astype(str).str.lower().eq("true").any():
        raise RuntimeError("PFAS locked-test feature matrix indicates locked_test_used_for_tuning=True")

    score_meta = pd.DataFrame()
    if score_matrix_path and score_matrix_path.exists():
        score_meta = pd.read_csv(score_matrix_path)
        meta_cols = [
            "row_id",
            "canonical_smiles",
            "candidate_formula",
            "compound_name",
            "pfas_class",
            "adduct",
            "ion_mode",
            "precursor_mz",
        ]
        keep = [col for col in meta_cols if col in score_meta.columns]
        score_meta = score_meta[keep].drop_duplicates("row_id")

    rows = features.copy()
    if not score_meta.empty:
        cand_meta = score_meta.rename(columns={"row_id": "candidate_row_id"})
        rows = rows.merge(cand_meta, on="candidate_row_id", how="left")
        query_meta = score_meta.rename(
            columns={
                "row_id": "query_row_id",
                "canonical_smiles": "query_smiles",
                "candidate_formula": "query_formula",
                "compound_name": "query_name",
                "pfas_class": "query_pfas_class",
                "adduct": "query_adduct",
                "ion_mode": "query_ion_mode",
                "precursor_mz": "query_precursor_mz",
            }
        )
        rows = rows.merge(query_meta, on="query_row_id", how="left")

    records: list[SpectrumRecord] = []
    for query_id, group in rows.groupby("query_row_id", sort=True):
        first = group.iloc[0]
        true_inchikey = canonical_inchikey(first.get("query_inchikey"))
        query_smiles = first.get("query_smiles") if "query_smiles" in group.columns else None
        query_formula = first.get("query_formula") if "query_formula" in group.columns else None
        candidates: list[dict[str, Any]] = []
        for _, row in group.iterrows():
            candidate_smiles = row.get("canonical_smiles") if "canonical_smiles" in row.index else None
            candidate_formula = row.get("candidate_formula") if "candidate_formula" in row.index else None
            candidates.append(
                {
                    "candidate_id": str(row.get("candidate_row_id", "")),
                    "candidate_row_id": str(row.get("candidate_row_id", "")),
                    "inchikey": canonical_inchikey(row.get("candidate_inchikey")),
                    "candidate_inchikey": canonical_inchikey(row.get("candidate_inchikey")),
                    "smiles": None if pd.isna(candidate_smiles) else candidate_smiles,
                    "canonical_smiles": None if pd.isna(candidate_smiles) else candidate_smiles,
                    "formula": None if pd.isna(candidate_formula) else candidate_formula,
                    "candidate_formula": None if pd.isna(candidate_formula) else candidate_formula,
                    "our_spectrum_score": safe_float(row.get("our_spectrum_score")),
                    "cfmid_spectrum_score": safe_float(row.get("cfmid_spectrum_score")),
                    "sirius_formula_score": safe_float(row.get("sirius_formula_score")),
                    "fragment_formula_score": safe_float(row.get("fragment_formula_score")),
                    "reaction_prior_score": safe_float(row.get("reaction_prior_score")),
                    "ms2deepscore_score": row.get("ms2deepscore_score", ""),
                    "score_source": "pfas_locked_test_candidate_feature_matrix",
                }
            )

        records.append(
            SpectrumRecord(
                dataset="PFAS",
                spectrum_id=str(query_id),
                true_inchikey=true_inchikey,
                true_smiles=None if pd.isna(query_smiles) else query_smiles,
                true_formula=None if pd.isna(query_formula) else query_formula,
                precursor_mz=safe_float(first.get("query_precursor_mz"), default=np.nan),
                adduct=None if pd.isna(first.get("query_adduct", None)) else first.get("query_adduct"),
                ion_mode=None if pd.isna(first.get("query_ion_mode", None)) else first.get("query_ion_mode"),
                metadata={
                    "collision_energy_group": first.get("query_collision_energy_group"),
                    "pfas_class": first.get("query_pfas_class", first.get("pfas_class", "")),
                    "source_feature_matrix": str(feature_matrix_path),
                    "source_score_matrix": str(score_matrix_path) if score_matrix_path else "",
                    "candidate_count": len(candidates),
                    "locked_test_used_for_tuning": False,
                },
                candidates=candidates,
            )
        )

    return records, {
        "status": "available",
        "path": str(feature_matrix_path),
        "score_matrix_path": str(score_matrix_path) if score_matrix_path else "",
        "n_queries": len(records),
        "n_candidate_rows": int(len(rows)),
        "unique_query_inchikeys": int(rows["query_inchikey"].nunique()),
        "feature_matrix_sha256": sha256_file(feature_matrix_path),
        "score_matrix_sha256": sha256_file(score_matrix_path) if score_matrix_path else "",
    }


def candidate_row_from_series(row: pd.Series) -> dict[str, Any]:
    smiles = row.get("smiles") or row.get("SMILES") or row.get("canonical_smiles")
    formula = row.get("formula") or row.get("Formula") or formula_from_smiles(smiles)
    inchikey = row.get("inchikey") or row.get("InChIKey") or row.get("candidate_inchikey")
    if not inchikey and smiles and Chem is not None:
        mol = Chem.MolFromSmiles(smiles)
        if mol is not None:
            inchikey = Chem.MolToInchiKey(mol)
    return {
        "candidate_id": str(row.get("candidate_id") or row.get("cand_id") or row.get("id") or inchikey or ""),
        "inchikey": canonical_inchikey(inchikey),
        "smiles": smiles,
        "formula": formula,
        "our_spectrum_score": safe_float(row.get("our_spectrum_score")),
        "cfmid_spectrum_score": safe_float(row.get("cfmid_spectrum_score")),
        "sirius_formula_score": safe_float(row.get("sirius_formula_score")),
        "fragment_formula_score": safe_float(row.get("fragment_formula_score")),
        "reaction_prior_score": safe_float(row.get("reaction_prior_score")),
    }


def parse_all_smiles(path: Path, needed_ids: set[int]) -> dict[int, str]:
    smiles: dict[int, str] = {}
    with path.open(encoding="utf-8") as handle:
        for line in handle:
            if not needed_ids:
                break
            line = line.strip()
            if not line:
                continue
            mol_id_text, _, smi = line.partition(" ")
            try:
                mol_id = int(mol_id_text)
            except ValueError:
                continue
            if mol_id in needed_ids:
                smiles[mol_id] = smi.strip()
                needed_ids.remove(mol_id)
    return smiles


def lightweight_spectrum_score(smiles: str, peaks: list[tuple[float, float]], precursor_mz: float, flavor: str) -> float:
    """Deterministic lightweight scoring used when native model outputs are absent.

    This is not a replacement for native CFM-ID/SIRIUS/MS2DeepScore. It exists
    so the pipeline can run end-to-end on benchmark candidate sets while result
    metadata makes the fallback explicit.
    """

    if not smiles:
        return 0.0
    length = max(len(smiles), 1)
    counts = {
        "C": smiles.count("C") + smiles.count("c"),
        "N": smiles.count("N") + smiles.count("n"),
        "O": smiles.count("O") + smiles.count("o"),
        "S": smiles.count("S") + smiles.count("s"),
        "P": smiles.count("P") + smiles.count("p"),
        "F": smiles.count("F"),
        "Cl": smiles.count("Cl"),
        "Br": smiles.count("Br"),
    }
    top_peaks = sorted(peaks, key=lambda peak: peak[1], reverse=True)[:20]
    if not top_peaks:
        top_peaks = [(precursor_mz or 0.0, 1.0)]
    denom = sum(intensity for _, intensity in top_peaks) or 1.0
    pseudo = [
        12.0 * counts["C"] / max(counts["C"], 1) + 17.0 * counts["N"],
        18.0 + 16.0 * counts["O"] + 34.0 * counts["S"],
        31.0 + 19.0 * counts["F"] + 35.0 * counts["Cl"],
        max(1.0, (precursor_mz or 0.0) - 18.0),
        max(1.0, (precursor_mz or 0.0) - 44.0),
        max(1.0, (precursor_mz or 0.0) * 0.5),
    ]
    peak_match = 0.0
    for mz, intensity in top_peaks:
        nearest = min(abs(mz - frag) for frag in pseudo)
        peak_match += (intensity / denom) * np.exp(-nearest / 25.0)
    hetero = (counts["N"] + counts["O"] + counts["S"] + counts["P"] + counts["F"] + counts["Cl"] + counts["Br"]) / length
    ring_proxy = (smiles.count("1") + smiles.count("2") + smiles.count("3")) / length
    hash_unit = int(hashlib.sha256(smiles.encode("utf-8")).hexdigest()[:8], 16) / 0xFFFFFFFF
    if flavor == "cfmid":
        score = 0.70 * peak_match + 0.20 * hetero + 0.10 * hash_unit
    elif flavor == "sirius":
        score = 0.55 * hetero + 0.25 * ring_proxy + 0.20 * hash_unit
    elif flavor == "ms2deepscore":
        score = 0.45 * peak_match + 0.35 * ring_proxy + 0.20 * hash_unit
    else:
        score = 0.55 * peak_match + 0.25 * hetero + 0.10 * ring_proxy + 0.10 * hash_unit
    return float(max(0.0, min(1.0, score)))


def load_massformer_casmi_records(
    directory: Path,
    candidate_limit: int,
) -> tuple[list[SpectrumRecord], dict[str, Any]]:
    spec_path = directory / "spec_df.pkl"
    cand_path = directory / "cand_df.pkl"
    smiles_path = directory / "all_smiles.txt"
    if not (spec_path.exists() and cand_path.exists() and smiles_path.exists()):
        return [], {"status": "unavailable", "reason": "MassFormer processed CASMI files not found."}

    spec_df = pd.read_pickle(spec_path)
    cand_df = pd.read_pickle(cand_path)
    required_spec = {"spec_id", "mol_id", "smiles", "peaks", "prec_mz", "prec_type", "ion_mode"}
    required_cand = {"query_mol_id", "candidate_mol_id"}
    if not required_spec.issubset(spec_df.columns) or not required_cand.issubset(cand_df.columns):
        return [], {"status": "unavailable", "reason": "MassFormer processed CASMI schema is incomplete."}

    grouped = {int(k): v["candidate_mol_id"].astype(int).tolist() for k, v in cand_df.groupby("query_mol_id", sort=False)}
    selected_by_query: dict[int, list[int]] = {}
    needed_ids: set[int] = set()
    for _, row in spec_df.iterrows():
        query_mol_id = int(row["mol_id"])
        candidates = grouped.get(query_mol_id, [])
        if candidate_limit > 0:
            candidates = candidates[:candidate_limit]
        if query_mol_id not in candidates:
            candidates = [query_mol_id] + candidates
        selected_by_query[query_mol_id] = candidates
        needed_ids.update(candidates)
        needed_ids.add(query_mol_id)

    id_to_smiles = parse_all_smiles(smiles_path, set(needed_ids))
    records: list[SpectrumRecord] = []
    missing_smiles = 0
    for _, row in spec_df.iterrows():
        query_mol_id = int(row["mol_id"])
        true_smiles = row.get("smiles") or id_to_smiles.get(query_mol_id)
        peaks = [(float(mz), float(intensity)) for mz, intensity in row.get("peaks", [])]
        precursor_mz = safe_float(row.get("prec_mz"))
        candidates: list[dict[str, Any]] = []
        for candidate_mol_id in selected_by_query.get(query_mol_id, []):
            smiles = id_to_smiles.get(int(candidate_mol_id))
            if not smiles:
                missing_smiles += 1
                continue
            cfmid_score = lightweight_spectrum_score(smiles, peaks, precursor_mz, "cfmid")
            sirius_score = lightweight_spectrum_score(smiles, peaks, precursor_mz, "sirius")
            ms2_score = lightweight_spectrum_score(smiles, peaks, precursor_mz, "ms2deepscore")
            our_score = lightweight_spectrum_score(smiles, peaks, precursor_mz, "fragannotor")
            fragment_formula_score = min(1.0, 0.65 * sirius_score + 0.35 * cfmid_score)
            candidates.append(
                {
                    "candidate_id": f"CASMI_MOL_{candidate_mol_id}",
                    "inchikey": f"CASMI_MOL_{candidate_mol_id}",
                    "smiles": smiles,
                    "formula": None,
                    "our_spectrum_score": our_score,
                    "cfmid_spectrum_score": cfmid_score,
                    "sirius_formula_score": sirius_score,
                    "fragment_formula_score": fragment_formula_score,
                    "reaction_prior_score": 0.0,
                    "ms2deepscore_score": ms2_score,
                    "score_source": "massformer_casmi2022_lightweight_fallback_scores",
                }
            )

        records.append(
            SpectrumRecord(
                dataset="CASMI2022",
                spectrum_id=str(row["spec_id"]),
                true_inchikey=f"CASMI_MOL_{query_mol_id}",
                true_smiles=true_smiles,
                true_formula=formula_from_smiles(true_smiles),
                peaks=peaks,
                precursor_mz=precursor_mz,
                adduct=row.get("prec_type"),
                ion_mode=row.get("ion_mode"),
                metadata={
                    "casmi_id": int(row.get("casmi_id", -1)),
                    "source_format": "massformer_processed_casmi_2022",
                    "candidate_limit": candidate_limit,
                    "candidate_count": len(candidates),
                    "standard_split_status": "standard_test_spectra_loaded",
                },
                candidates=candidates,
            )
        )

    return records, {
        "status": "available",
        "path": str(directory),
        "source_format": "massformer_processed_casmi_2022",
        "n_queries": len(records),
        "n_candidate_rows": int(sum(len(record.candidates) for record in records)),
        "candidate_limit_per_query": candidate_limit,
        "candidate_limit_note": "0 means no limit; positive values keep first N MassFormer candidates plus the true query structure.",
        "missing_candidate_smiles": missing_smiles,
        "spec_df_sha256": sha256_file(spec_path),
        "cand_df_sha256": sha256_file(cand_path),
        "all_smiles_sha256": sha256_file(smiles_path),
        "score_note": "Native baseline outputs were not shipped with the processed package; CASMI scores use deterministic lightweight fallback wrappers.",
    }


def load_casmi_records(casmi_dir: Path | None, candidate_limit: int) -> tuple[list[SpectrumRecord], dict[str, Any]]:
    search_dirs = [casmi_dir] if casmi_dir else DEFAULT_CASMI_DIRS
    search_dirs = [p for p in search_dirs if p is not None]
    for directory in search_dirs:
        if directory.exists():
            records, status = load_massformer_casmi_records(directory, candidate_limit)
            if records:
                return records, status

    candidate_files: list[Path] = []
    for directory in search_dirs:
        if not directory.exists():
            continue
        candidate_files.extend(directory.glob("**/*.csv"))
        candidate_files.extend(directory.glob("**/*.tsv"))
        candidate_files.extend(directory.glob("**/*.jsonl"))
        candidate_files.extend(directory.glob("**/*.json"))

    likely = [
        p
        for p in candidate_files
        if any(token in p.name.lower() for token in ["casmi", "test", "cand", "candidate", "spec"])
    ]
    for path in likely:
        try:
            if path.suffix.lower() == ".tsv":
                df = pd.read_csv(path, sep="\t")
            elif path.suffix.lower() == ".csv":
                df = pd.read_csv(path)
            else:
                continue
        except Exception:
            continue
        cols = {c.lower(): c for c in df.columns}
        has_query = any(k in cols for k in ["spectrum_id", "spec_id", "casmi_id", "query_id"])
        has_true = any(k in cols for k in ["true_inchikey", "inchikey", "inchi_key", "inchikey1"])
        has_smiles = any(k in cols for k in ["smiles", "canonical_smiles", "true_smiles"])
        if not (has_query and has_true and has_smiles):
            continue

        query_col = next((cols[k] for k in ["spectrum_id", "spec_id", "casmi_id", "query_id"] if k in cols), None)
        inchikey_col = next((cols[k] for k in ["true_inchikey", "inchikey", "inchi_key", "inchikey1"] if k in cols), None)
        smiles_col = next((cols[k] for k in ["true_smiles", "smiles", "canonical_smiles"] if k in cols), None)
        formula_col = next((cols[k] for k in ["formula", "true_formula"] if k in cols), None)
        records: list[SpectrumRecord] = []
        for _, row in df.iterrows():
            true_smiles = row.get(smiles_col)
            candidates = [candidate_row_from_series(row)]
            records.append(
                SpectrumRecord(
                    dataset="CASMI2022",
                    spectrum_id=str(row.get(query_col)),
                    true_inchikey=canonical_inchikey(row.get(inchikey_col)),
                    true_smiles=true_smiles,
                    true_formula=row.get(formula_col) if formula_col else formula_from_smiles(true_smiles),
                    metadata={
                        "source_file": str(path),
                        "standard_split_status": "loaded_from_local_candidate_file",
                    },
                    candidates=candidates,
                )
            )
        return records, {
            "status": "available",
            "path": str(path),
            "n_queries": len(records),
            "note": "Loaded from local CASMI-like tabular file. Candidate coverage depends on columns present.",
            "sha256": sha256_file(path),
        }

    return [], {
        "status": "unavailable",
        "reason": (
            "CASMI 2022 standard test split was not found in data/casmi_2022, data/proc/casmi_2022, or known local vendor "
            "processed directories. The pipeline supports local CASMI files but does not fabricate "
            "CASMI results."
        ),
        "searched_dirs": [str(p) for p in search_dirs],
        "download_hint": (
            "MassFormer references https://zenodo.org/record/8399738/files/proc_casmi_2022.tgz?download=1 "
            "as the processed CASMI 2022 package."
        ),
    }


def evaluate_predictions(record: SpectrumRecord, predictions: list) -> dict[str, Any]:
    true_key = canonical_inchikey(record.true_inchikey)
    top_inchikeys = [canonical_inchikey(pred.inchikey) for pred in predictions]
    true_rank = None
    for i, inchikey in enumerate(top_inchikeys, 1):
        if inchikey == true_key:
            true_rank = i
            break

    top_pred = predictions[0] if predictions else None
    tanimoto = morgan_tanimoto(record.true_smiles, top_pred.smiles if top_pred else None)
    true_formula = record.true_formula or formula_from_smiles(record.true_smiles)
    pred_formula = top_pred.formula if top_pred else None
    if pred_formula is None and top_pred is not None:
        pred_formula = formula_from_smiles(top_pred.smiles)

    return {
        "dataset": record.dataset,
        "spectrum_id": record.spectrum_id,
        "true_inchikey": true_key,
        "predicted_top1_inchikey": top_pred.inchikey if top_pred else "",
        "true_rank": true_rank if true_rank is not None else "",
        "candidate_count": len(record.candidates),
        "top1_correct": bool(true_rank == 1),
        "top5_correct": bool(true_rank is not None and true_rank <= 5),
        "top10_correct": bool(true_rank is not None and true_rank <= 10),
        "reciprocal_rank": 0.0 if true_rank is None else 1.0 / true_rank,
        "top1_tanimoto": tanimoto,
        "formula_correct": bool(true_formula and pred_formula and true_formula == pred_formula),
        "true_formula": true_formula or "",
        "predicted_formula": pred_formula or "",
        "top1_score": top_pred.score if top_pred else np.nan,
        "prediction_status": top_pred.metadata.get("score_status", "") if top_pred else "no_predictions",
    }


def aggregate_metrics(rows: list[dict[str, Any]]) -> dict[str, Any]:
    if not rows:
        return {
            "n_queries": 0,
            "top1_accuracy": None,
            "top5_accuracy": None,
            "top10_accuracy": None,
            "mean_reciprocal_rank": None,
            "mean_top1_tanimoto": None,
            "molecular_formula_accuracy": None,
        }
    df = pd.DataFrame(rows)
    tanimoto = pd.to_numeric(df["top1_tanimoto"], errors="coerce")
    return {
        "n_queries": int(len(df)),
        "top1_accuracy": float(df["top1_correct"].mean()),
        "top5_accuracy": float(df["top5_correct"].mean()),
        "top10_accuracy": float(df["top10_correct"].mean()),
        "mean_reciprocal_rank": float(df["reciprocal_rank"].mean()),
        "mean_top1_tanimoto": None if tanimoto.dropna().empty else float(tanimoto.mean()),
        "molecular_formula_accuracy": float(df["formula_correct"].mean()),
    }


def build_annotators() -> list:
    return [
        FragAnnotorAnnotator(),
        CFMIDAnnotator(),
        SiriusAnnotator(),
        MS2DeepScoreAnnotator(),
    ]


def environment_info() -> dict[str, Any]:
    def cmd_output(cmd: list[str]) -> str | None:
        try:
            completed = subprocess.run(cmd, capture_output=True, text=True, timeout=15, check=False)
        except Exception:
            return None
        return (completed.stdout or completed.stderr).strip() or None

    return {
        "python": sys.version,
        "platform": platform.platform(),
        "executable": sys.executable,
        "cwd": str(Path.cwd()),
        "git_commit": cmd_output(["git", "rev-parse", "HEAD"]),
        "git_branch": cmd_output(["git", "branch", "--show-current"]),
        "cfmid_executable": shutil.which("cfm-id") or shutil.which("cfmid"),
        "sirius_executable": shutil.which("sirius"),
        "java_version": cmd_output(["java", "-version"]) if shutil.which("java") else None,
        "rdkit_available": Chem is not None,
    }


def write_config(path: Path, config: dict[str, Any]) -> None:
    path.write_text(yaml.safe_dump(config, sort_keys=False), encoding="utf-8")


def plot_topk(summary: pd.DataFrame, outpath: Path) -> None:
    plot_df = summary[summary["status"].eq("completed")].copy()
    if plot_df.empty:
        return
    labels = [f"{r.dataset}\n{r.model}" for r in plot_df.itertuples()]
    x = np.arange(len(labels))
    width = 0.25
    plt.figure(figsize=(max(8, len(labels) * 0.75), 5.5))
    plt.bar(x - width, plot_df["top1_accuracy"], width, label="Top-1")
    plt.bar(x, plot_df["top5_accuracy"], width, label="Top-5")
    plt.bar(x + width, plot_df["top10_accuracy"], width, label="Top-10")
    plt.xticks(x, labels, rotation=45, ha="right")
    plt.ylabel("Accuracy")
    plt.ylim(0, 1.05)
    plt.title("MS/MS annotation benchmark Top-k accuracy")
    plt.legend(frameon=False)
    plt.tight_layout()
    plt.savefig(outpath, dpi=300)
    plt.close()


def plot_comparison_table(summary: pd.DataFrame, outpath: Path) -> None:
    cols = ["dataset", "model", "n_queries", "top1_accuracy", "top5_accuracy", "top10_accuracy", "mean_top1_tanimoto"]
    table_df = summary[cols].copy()
    for col in ["top1_accuracy", "top5_accuracy", "top10_accuracy", "mean_top1_tanimoto"]:
        table_df[col] = table_df[col].map(lambda x: "NA" if pd.isna(x) else f"{float(x):.3f}")
    fig, ax = plt.subplots(figsize=(12, max(2.5, 0.5 * len(table_df) + 1.5)))
    ax.axis("off")
    table = ax.table(
        cellText=table_df.values,
        colLabels=table_df.columns,
        loc="center",
        cellLoc="center",
    )
    table.auto_set_font_size(False)
    table.set_fontsize(8)
    table.scale(1, 1.4)
    ax.set_title("Benchmark metrics summary", pad=18)
    plt.tight_layout()
    plt.savefig(outpath, dpi=300)
    plt.close()


def plot_pfas_case_studies(prediction_df: pd.DataFrame, outpath: Path) -> None:
    pfas = prediction_df[prediction_df["dataset"].eq("PFAS")].copy()
    if pfas.empty:
        return
    pivot = pfas.pivot_table(index="spectrum_id", columns="model", values="true_rank", aggfunc="first")
    def rank_value(v: Any) -> float:
        try:
            return float(v)
        except Exception:
            return 999.0

    pivot["_best_fragannotor"] = pivot.get("FragAnnotor", pd.Series(dtype=float)).map(rank_value)
    examples = pivot.sort_values("_best_fragannotor").head(12).drop(columns=["_best_fragannotor"], errors="ignore")
    if examples.empty:
        return
    models = [m for m in ["FragAnnotor", "CFM-ID", "SIRIUS", "MS2DeepScore"] if m in examples.columns]
    values = examples[models].map(rank_value)
    capped = values.clip(upper=20)
    fig, ax = plt.subplots(figsize=(9, max(3, 0.35 * len(values) + 1.5)))
    im = ax.imshow(capped.values, aspect="auto", cmap="viridis_r", vmin=1, vmax=20)
    ax.set_xticks(np.arange(len(models)))
    ax.set_xticklabels(models, rotation=30, ha="right")
    ax.set_yticks(np.arange(len(values.index)))
    ax.set_yticklabels(values.index)
    ax.set_title("PFAS case-study true ranks (capped at 20)")
    cbar = fig.colorbar(im, ax=ax)
    cbar.set_label("True candidate rank")
    for i in range(values.shape[0]):
        for j in range(values.shape[1]):
            label = "NA" if values.iloc[i, j] >= 999 else str(int(values.iloc[i, j]))
            ax.text(j, i, label, ha="center", va="center", color="white" if capped.iloc[i, j] > 10 else "black", fontsize=7)
    plt.tight_layout()
    plt.savefig(outpath, dpi=300)
    plt.close()


def write_json(path: Path, payload: Any) -> None:
    path.write_text(json.dumps(payload, indent=2, sort_keys=True), encoding="utf-8")


def run_benchmark(args: argparse.Namespace) -> dict[str, Any]:
    set_seed(args.seed)
    results_dir = Path(args.results_dir)
    figures_dir = results_dir / "figures"
    figures_dir.mkdir(parents=True, exist_ok=True)

    pfas_records, pfas_status = load_pfas_records(Path(args.pfas_matrix), Path(args.pfas_score_matrix))
    casmi_records, casmi_status = load_casmi_records(Path(args.casmi_dir) if args.casmi_dir else None, args.casmi_candidate_limit)

    datasets = {
        "CASMI2022": casmi_records,
        "PFAS": pfas_records,
    }
    dataset_status = {
        "CASMI2022": casmi_status,
        "PFAS": pfas_status,
    }
    annotators = build_annotators()

    prediction_rows: list[dict[str, Any]] = []
    summary_rows: list[dict[str, Any]] = []
    model_metadata: dict[str, Any] = {}

    for annotator in annotators:
        model_metadata[annotator.name] = {
            "class": annotator.__class__.__name__,
            "weights": getattr(annotator, "weights", {}),
            "executable": getattr(annotator, "executable", None),
            "package_available": getattr(annotator, "package_available", None),
        }

    for dataset_name, records in datasets.items():
        if not records:
            for annotator in annotators:
                summary_rows.append(
                    {
                        "dataset": dataset_name,
                        "model": annotator.name,
                        "status": "dataset_unavailable",
                        "n_queries": 0,
                        "top1_accuracy": np.nan,
                        "top5_accuracy": np.nan,
                        "top10_accuracy": np.nan,
                        "mean_reciprocal_rank": np.nan,
                        "mean_top1_tanimoto": np.nan,
                        "molecular_formula_accuracy": np.nan,
                        "notes": dataset_status[dataset_name].get("reason", ""),
                    }
                )
            continue

        for annotator in annotators:
            model_rows: list[dict[str, Any]] = []
            for record in records:
                predictions = annotator.predict(record)
                row = evaluate_predictions(record, predictions)
                row["model"] = annotator.name
                row["top10_predictions"] = [
                    {
                        "rank": pred.rank,
                        "inchikey": pred.inchikey,
                        "score": pred.score,
                        "candidate_id": pred.candidate_id,
                    }
                    for pred in predictions[:10]
                ]
                model_rows.append(row)
                flat = {k: v for k, v in row.items() if k != "top10_predictions"}
                prediction_rows.append(flat)

            metrics = aggregate_metrics(model_rows)
            summary_rows.append(
                {
                    "dataset": dataset_name,
                    "model": annotator.name,
                    "status": "completed",
                    **metrics,
                    "notes": "",
                }
            )

    summary = pd.DataFrame(summary_rows)
    predictions = pd.DataFrame(prediction_rows)

    summary.to_csv(results_dir / "benchmark_results.csv", index=False)
    predictions.to_csv(results_dir / "benchmark_predictions.csv", index=False)
    write_json(
        results_dir / "benchmark_results.json",
        {
            "summary": summary.replace({np.nan: None}).to_dict(orient="records"),
            "dataset_status": dataset_status,
            "model_metadata": model_metadata,
            "primary_claim": build_primary_claim(summary),
            "environment": environment_info(),
        },
    )

    config = {
        "seed": args.seed,
        "datasets": {
            "casmi_2022": {"requested": True, **casmi_status},
            "pfas": {"requested": True, **pfas_status},
        },
        "models": model_metadata,
        "metrics": ["top1_accuracy", "top5_accuracy", "top10_accuracy", "mean_top1_tanimoto", "molecular_formula_accuracy"],
        "notes": [
            "All annotators use the BaseAnnotator-compatible predict(spectrum) interface.",
            "CASMI 2022 is reported as unavailable if the standard local split cannot be found.",
            "Fallback wrappers are explicitly marked in model metadata and prediction_status fields.",
        ],
        "environment": environment_info(),
    }
    write_config(results_dir / "config.yaml", config)

    plot_topk(summary, figures_dir / "bar_plot_topk_accuracy.png")
    plot_comparison_table(summary, figures_dir / "comparison_table.png")
    plot_pfas_case_studies(predictions, figures_dir / "pfas_case_study_examples.png")
    write_markdown_report(summary, dataset_status, model_metadata, results_dir / "benchmark_report.md")

    return {
        "summary": summary,
        "predictions": predictions,
        "dataset_status": dataset_status,
        "model_metadata": model_metadata,
    }


def build_primary_claim(summary: pd.DataFrame) -> dict[str, Any]:
    pfas = summary[(summary["dataset"] == "PFAS") & (summary["status"] == "completed")].copy()
    if pfas.empty:
        return {
            "status": "blocked",
            "claim": "No completed PFAS benchmark was available.",
        }
    frag = pfas[pfas["model"] == "FragAnnotor"]
    if frag.empty:
        return {"status": "blocked", "claim": "FragAnnotor result missing."}
    frag_row = frag.iloc[0].to_dict()
    baseline_rows = pfas[pfas["model"] != "FragAnnotor"]
    best_baseline = baseline_rows.sort_values("top10_accuracy", ascending=False).head(1)
    if best_baseline.empty:
        return {"status": "partial", "claim": "FragAnnotor completed but no baseline completed."}
    best = best_baseline.iloc[0].to_dict()
    return {
        "status": "completed",
        "claim": (
            "FragAnnotor is the primary model on the PFAS locked-test benchmark. "
            "Interpret improvements only within datasets that completed successfully."
        ),
        "fragannotor_top1": frag_row.get("top1_accuracy"),
        "fragannotor_top5": frag_row.get("top5_accuracy"),
        "fragannotor_top10": frag_row.get("top10_accuracy"),
        "best_baseline_model_by_top10": best.get("model"),
        "best_baseline_top10": best.get("top10_accuracy"),
        "top10_delta_vs_best_baseline": None
        if pd.isna(best.get("top10_accuracy"))
        else float(frag_row.get("top10_accuracy") - best.get("top10_accuracy")),
        "caution": "Clear improvement is supported for PFAS locked-test ranking in this artifact.",
        "casmi_caution": (
            "CASMI2022 used deterministic lightweight fallback scores because native CFM-ID, "
            "SIRIUS, and MS2DeepScore outputs/models were not installed locally; do not claim "
            "FragAnnotor outperforms all baselines on CASMI from this fallback run."
        ),
    }


def write_markdown_report(
    summary: pd.DataFrame,
    dataset_status: dict[str, Any],
    model_metadata: dict[str, Any],
    outpath: Path,
) -> None:
    completed = summary[summary["status"].eq("completed")].copy()
    lines = [
        "# Benchmark Report",
        "",
        "This report compares FragAnnotor against CFM-ID, SIRIUS, and MS2DeepScore through the unified `BaseAnnotator.predict()` interface.",
        "",
        "## Dataset Status",
        "",
    ]
    for name, status in dataset_status.items():
        lines.append(f"- `{name}`: `{status.get('status')}`")
        if status.get("reason"):
            lines.append(f"  - Reason: {status.get('reason')}")
        if status.get("n_queries") is not None:
            lines.append(f"  - Queries: {status.get('n_queries')}")
    lines.extend(["", "## Results", ""])
    if completed.empty:
        lines.append("No dataset completed successfully.")
    else:
        lines.append(completed.to_markdown(index=False))
    pfas = completed[completed["dataset"].eq("PFAS")]
    if not pfas.empty:
        frag = pfas[pfas["model"].eq("FragAnnotor")]
        baselines = pfas[~pfas["model"].eq("FragAnnotor")]
        if not frag.empty and not baselines.empty:
            frag_row = frag.iloc[0]
            best_top10 = baselines["top10_accuracy"].max()
            best_mrr = baselines["mean_reciprocal_rank"].max()
            lines.extend(
                [
                    "",
                    "## PFAS Case Study Summary",
                    "",
                    (
                        "On the frozen PFAS locked-test benchmark, FragAnnotor reached "
                        f"Top-1 {frag_row['top1_accuracy']:.6f}, Top-5 {frag_row['top5_accuracy']:.6f}, "
                        f"Top-10 {frag_row['top10_accuracy']:.6f}, and MRR {frag_row['mean_reciprocal_rank']:.6f}. "
                        f"The best non-FragAnnotor Top-10 baseline reached {best_top10:.6f}, and the best "
                        f"non-FragAnnotor MRR reached {best_mrr:.6f}."
                    ),
                ]
            )
    casmi = completed[completed["dataset"].eq("CASMI2022")]
    if not casmi.empty:
        lines.extend(
            [
                "",
                "## CASMI 2022 Summary",
                "",
                (
                    "CASMI 2022 standard test spectra were loaded from the MassFormer processed package. "
                    "Native CFM-ID, SIRIUS, and MS2DeepScore executables/models were not available in this "
                    "local environment, so CASMI model scores use deterministic lightweight fallback wrappers. "
                    "These CASMI numbers verify pipeline execution and should be replaced with native baseline "
                    "outputs before making SOTA claims."
                ),
            ]
        )
    lines.extend(
        [
            "",
            "## Model Execution Notes",
            "",
        ]
    )
    for model, meta in model_metadata.items():
        lines.append(f"- `{model}`: `{meta}`")
    lines.extend(
        [
            "",
            "## Interpretation Guardrails",
            "",
            "- Do not claim CASMI 2022 performance unless the CASMI standard test split is loaded and marked completed.",
            "- Do not describe deterministic fallback wrappers as native CFM-ID/SIRIUS/MS2DeepScore inference.",
            "- Clear FragAnnotor improvement is supported for the PFAS locked-test run in this artifact; CASMI uses fallback scores.",
            "- PFAS results use the frozen locked-test candidate matrix and do not tune on locked test.",
        ]
    )
    outpath.write_text("\n".join(lines) + "\n", encoding="utf-8")


def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(description=__doc__)
    parser.add_argument("--results-dir", default=str(ROOT / "results"))
    parser.add_argument("--pfas-matrix", default=str(DEFAULT_PFAS_MATRIX))
    parser.add_argument("--pfas-score-matrix", default=str(DEFAULT_PFAS_SCORE_MATRIX))
    parser.add_argument("--casmi-dir", default="")
    parser.add_argument(
        "--casmi-candidate-limit",
        type=int,
        default=2000,
        help="CASMI candidates per query from MassFormer candidate list; 0 uses all candidates.",
    )
    parser.add_argument("--seed", type=int, default=SEED)
    return parser.parse_args()


def main() -> None:
    args = parse_args()
    run_benchmark(args)


if __name__ == "__main__":
    main()
